const councils = [
  { name: 'Windsor & Maidenhead', auth: 'Windsor' },
  { name: 'Hillingdon',           auth: 'Hillingdon' },
  { name: 'Dacorum',              auth: 'Dacorum' },
  { name: 'Wokingham',            auth: 'Wokingham' },
  { name: 'Surrey Heath',         auth: 'SurreyHeath' },
  { name: 'Runnymede',            auth: 'Runnymede' }
];
const run_id = new Date().toISOString().replace(/[:.]/g, '-');
return [{ json: { council_index: 0, councils, run_id, total: councils.length } }];

const raw = $input.first().json;
const data = raw.body ? raw.body : raw;
const index = data.council_index ?? 0;
const councils = data.councils;
const run_id = data.run_id;
const total = data.total;
if (!councils || !Array.isArray(councils)) {
  throw new Error('still missing: ' + JSON.stringify(Object.keys(raw)));
}
if (index >= total) {
  return [{ json: { _all_done: true, run_id, total } }];
}
const current = councils[index];
const nextIndex = index + 1;
return [{ json: { council_name: current.name, council_auth: current.auth, council_index: index, next_index: nextIndex, councils, run_id, total, is_last: nextIndex >= total } }];

const items = $input.all();
const first = items[0].json;
const loop = first._loop || first;
if (!loop.councils || !Array.isArray(loop.councils)) {
  throw new Error('Prepare Next Council lost councils array: ' + JSON.stringify(first));
}
const nextIndex = loop.next_index !== undefined ? loop.next_index : (loop.council_index + 1);
return [{ json: { council_index: nextIndex, next_index: nextIndex + 1, councils: loop.councils, run_id: loop.run_id, total: loop.total, is_last: (nextIndex + 1) >= loop.total } }];

const runId = $input.first().json.run_id || 'unknown';
const today = new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
return [{ json: { run_id: runId, completed_at: new Date().toISOString(), subject: `Planning Permission Run Complete — ${today}`, html_email: `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>body{font-family:Arial,sans-serif;max-width:700px;margin:0 auto;color:#333}h1{color:#1a4e8a;border-bottom:3px solid #1a4e8a;padding-bottom:10px}.box{background:#e8f4e8;border:1px solid #4caf50;padding:16px 20px;border-radius:6px;margin:20px 0}.footer{margin-top:40px;font-size:12px;color:#999;border-top:1px solid #eee;padding-top:10px}</style></head><body><h1>Planning Permission Run Complete</h1><div class="box"><strong>All councils have been scraped and processed.</strong><br><br>New qualified leads with enrichment and opportunity scores have been added to your Google Sheet.<br>Run ID: <code>${runId}</code><br>Completed: ${today}</div><p>Open your Google Sheet to view all new planning applications identified as opportunities, with AI scoring and enrichment data.</p><div class="footer">Planning Permission — Automated Run</div></body></html>` } }];

const allItems = $input.all();
const firstItem = allItems[0].json;
const dataObj = Array.isArray(firstItem) ? firstItem[0] : firstItem;
const loopData = $('Extract Current Council').first().json;
const councilName = loopData.council_name || 'Unknown';
const applications = dataObj.records;
if (!applications || applications.length === 0) {
  return [{ json: { _no_results: true, council: councilName, council_index: loopData.council_index, next_index: loopData.next_index, councils: loopData.councils, run_id: loopData.run_id, total: loopData.total, is_last: loopData.is_last } }];
}
const excludeDescKeywords = ['rear extension','side extension','front extension','single storey extension','two storey extension','double storey extension','loft conversion','dormer','hip to gable','porch','conservatory','orangery','garage conversion','internal alterations','internal works','roof alterations','roof lights','velux','discharge of condition','non material amendment','prior approval','lawful development certificate','listed building consent','commercial','industrial','retail','office','telecommunications','advertisement','signage','tree works','tree preservation','hedgerow','replacement windows','replacement doors'];
const excludeAppTypes = ['conditions','trees','advert','prior','ldc','listed','heritage'];
const includeKeywords = ['new dwelling','new dwellings','new house','new houses','new home','new homes','replacement dwelling','replacement house','new build','newbuild','erection of','residential development','residential units','new residential','demolition and erection','barn conversion','change of use to dwelling','change of use to residential','conversion to','subdivision','self build','self-build','custom build','affordable housing','mixed use'];
const potentialLeads = applications.filter(app => {
  const desc = (app.description || '').toLowerCase();
  const appType = (app.app_type || '').toLowerCase();
  const appState = (app.app_state || '').toLowerCase();
  if (appState === 'decided' || appState === 'withdrawn') return false;
  if (excludeAppTypes.some(t => appType.includes(t))) return false;
  if (excludeDescKeywords.some(kw => desc.includes(kw))) return false;
  if (!includeKeywords.some(kw => desc.includes(kw))) return false;
  return true;
});
if (potentialLeads.length === 0) {
  return [{ json: { _no_results: true, council: councilName, council_index: loopData.council_index, next_index: loopData.next_index, councils: loopData.councils, run_id: loopData.run_id, total: loopData.total, is_last: loopData.is_last } }];
}
return potentialLeads.map((app, i) => ({ json: { uid: app.uid, address: app.address, postcode: app.postcode, description: app.description, app_type: app.app_type, app_state: app.app_state, start_date: app.start_date, url: app.url, link: app.link, council: app.area_name || councilName, _loop: { council_index: loopData.council_index, next_index: loopData.next_index, councils: loopData.councils, run_id: loopData.run_id, total: loopData.total, is_last: loopData.is_last } } }));

const items = $input.all();
if (items.length === 1 && items[0].json._no_results) { return items; }
return items;

const aiOutput = $input.first().json.output;
let qualifiedUIDs;
try {
  const cleaned = aiOutput.replace(/```json|```/g, '').trim();
  qualifiedUIDs = JSON.parse(cleaned);
} catch (e) {
  qualifiedUIDs = aiOutput.match(/"[^"]+"/g)?.map(uid => uid.replace(/"/g, '')) || [];
}
if (!qualifiedUIDs || qualifiedUIDs.length === 0) {
  const loopState = $('Code Filter Stage ').first().json._loop || {};
  return [{ json: { _no_qualified: true, councils: loopState.councils, council_index: loopState.council_index, next_index: loopState.next_index, run_id: loopState.run_id, total: loopState.total, is_last: loopState.is_last } }];
}
const httpData = $('PlanIt API Request1').first().json;
const dataObj = Array.isArray(httpData) ? httpData[0] : httpData;
const originalData = dataObj.records || [];
const loopState = $('Code Filter Stage ').first().json._loop || {};
const qualifiedLeads = originalData.filter(app => qualifiedUIDs.includes(app.uid));
return qualifiedLeads.map(app => ({ json: { uid: app.uid, reference: app.uid, council: app.area_name || 'Unknown', address: app.address, postcode: app.postcode, description: app.description, app_type: app.app_type, app_state: app.app_state, app_size: app.app_size || null, start_date: app.start_date, target_decision_date: app.other_fields?.target_decision_date || null, applicant_name: app.applicant_name || null, applicant_address: app.applicant_address || null, agent_name: app.agent_name || null, agent_address: app.agent_address || null, planit_url: app.link || app.url, council_url: app.other_fields?.url || null, scraped_date: new Date().toISOString().split('T')[0], _loop: loopState } }));

// Merge original data + enrichment + opportunity scores
const originalLeads = $('Restore Full Data1').all().map(i => i.json);

// Parse enrichment output
const enrichRaw = $('AI: Enrich Leads').first().json.output || '';
let enrichments = [];
try {
  const cleaned = enrichRaw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  enrichments = Array.isArray(parsed) ? parsed : [];
} catch(e) { enrichments = []; }

// Parse score output (current input)
const scoreRaw = $input.first().json.output || '';
let scores = [];
try {
  const cleaned = scoreRaw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  scores = Array.isArray(parsed) ? parsed : [];
} catch(e) { scores = []; }

// Merge by uid
return originalLeads.map(app => {
  const enrich = enrichments.find(e => e.uid === app.uid) || {};
  const score = scores.find(s => s.uid === app.uid) || {};
  return {
    json: {
      uid: app.uid,
      reference: app.uid,
      council: app.council,
      address: app.address,
      postcode: app.postcode,
      description: app.description,
      app_type: app.app_type,
      app_state: app.app_state,
      app_size: app.app_size || null,
      start_date: app.start_date,
      target_decision_date: app.target_decision_date || null,
      applicant_name: app.applicant_name || null,
      applicant_address: app.applicant_address || null,
      agent_name: app.agent_name || null,
      agent_address: app.agent_address || null,
      planit_url: app.planit_url,
      council_url: app.council_url || null,
      scraped_date: app.scraped_date,
      unit_count: enrich.unit_count ?? null,
      dwelling_type: enrich.dwelling_type || null,
      development_scale: enrich.development_scale || null,
      applicant_type: enrich.applicant_type || null,
      enrichment_notes: enrich.notes || null,
      opportunity_score: score.score ?? null,
      priority: score.priority || null,
      score_reasoning: score.reasoning || null,
      processed_at: new Date().toISOString(),
      _loop: app._loop
    }
  };
});

// Google Sheets strips _loop, so retrieve it from Restore Full Data1
const loopState = $('Restore Full Data1').first().json._loop;
return [{ json: { councils: loopState.councils, council_index: loopState.council_index, next_index: loopState.next_index, run_id: loopState.run_id, total: loopState.total, is_last: loopState.is_last } }];
